"""
mkt-context layer — Acts chapters 4–6
Output: data/commentary/mkt-context/acts.json
Run: python3 scripts/zc-context-acts-4-6.py

Context layer focus: Second Temple institutional structures, Sanhedrin procedures,
social dynamics of the Jerusalem church, Hellenist-Hebrew tensions, and the Seven.
Ch 4 v36 and ch 5 v34 already present; merge_comm skips them.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH4_6 = {
"4": {
"1": "<p>The <em>captain of the temple guard</em> (<em>stratēgos tou hierou</em>) was a high-ranking priestly official second only to the high priest, responsible for security and order in the temple precincts. Josephus mentions the role frequently (<em>Ant.</em> 20.6.2; <em>J.W.</em> 2.17.2). The Sadducees (a priestly aristocratic party) and the temple captain respond together because Peter's proclamation in Solomon's Portico threatens both the institutional order they maintain and the theological framework they hold (Sadducees denied resurrection, v.2).</p>",
"2": "<p>The Sadducees' specific objection — that the apostles were 'proclaiming in Jesus the resurrection of the dead' (<em>katangellousin en tō Iēsou tēn anastasin</em>) — identifies the core theological dispute. The Sadducees accepted only the Pentateuch as binding and denied bodily resurrection (cf. Mark 12:18-27; Acts 23:8). The apostles' proclamation that Jesus had risen was simultaneously an empirical claim (a specific man rose) and a theological provocation (resurrection is real and has begun). For the Sadducean leadership, both the claim and the implication were intolerable.</p>",
"3": "<p>Evening arrest meant an overnight detention; Jewish law (m. Sanhedrin 4:1) required capital cases to begin and conclude before nightfall and never on a feast-day eve. Holding Peter and John until the next day kept the matter within normal judicial procedure while preventing the crowd from disrupting proceedings. Josephus describes similar tactical delays in politically sensitive arrests (<em>Ant.</em> 14.9.4).</p>",
"4": "<p>'Five thousand men' (<em>andrōn hōsei pentakischilioi</em>) — the count of <em>andres</em> (adult males) was the standard census-unit in antiquity; the total community including women would be larger. The rapid growth from 3,000 at Pentecost (2:41) to 5,000 after the lame man's healing illustrates Luke's consistent pattern of persecution followed by growth: the arrest of the leaders does not slow the mission but accelerates it. The Jerusalem church at this point represents a significant fraction of the city's Jewish population.</p>",
"5": "<p>The convening of 'rulers, elders and scribes' (<em>archontes, presbyteroi, grammateis</em>) describes the Sanhedrin's three constituent orders: (1) chief priests and high-priestly families (<em>archontes</em>), (2) tribal/lay elders (<em>presbyteroi</em>), and (3) legal scholars/scribes (<em>grammateis</em>). The Sanhedrin (<em>synedrion</em> = sitting-together) was the supreme Jewish council of Jerusalem, numbering 71 members according to m. Sanhedrin 1:6, with both judicial and legislative authority over Jewish life in Palestine.</p>",
"6": "<p>Annas had served as high priest from 6-15 CE before being deposed by the Romans; his son-in-law Caiaphas held the office 18-36 CE. Roman policy required annual high-priest appointments but Jewish tradition recognized the position as lifelong; Annas retained enormous de facto authority (cf. John 18:13, 24 where Jesus is brought to Annas first). The listing of Annas before Caiaphas reflects this reality: Annas was the effective head of the high-priestly clan that dominated Jerusalem's religious politics for decades.</p>",
"7": "<p>'By what power or what name' (<em>en poia dynamei ē en poiō onomati</em>) — the question combines two distinct categories: <em>dynamis</em> (power, the miraculous force employed) and <em>onoma</em> (name, the authority invoked). In ancient Jewish and Hellenistic magical practice, both components were essential: the power behind an act and the name by which that power was accessed. The Sanhedrin's question is simultaneously a legal investigation and a theological probe: whose authority do you invoke, and by what right?</p>",
"8": "<p>'Filled with the Holy Spirit' (<em>plēstheis pneumatos hagiou</em>) — Luke's pneumatological formula for empowered speech throughout Acts (2:4; 4:8, 31; 6:3, 5; 7:55; 9:17; 11:24; 13:9, 52). The address 'rulers and elders of the people' (<em>archontes tou laou kai presbyteroi</em>) uses the formal Sanhedrin designation from v.5, positioning Peter's response as an official defense (<em>apologia</em>) before the highest Jewish court — exactly the setting Jesus prophesied in Luke 12:11-12 ('when they bring you before... the authorities... the Holy Spirit will teach you what to say').</p>",
"9": "<p>'An act of kindness shown to a man who was lame' (<em>euergesiai anthrōpou asthenous</em>) — <em>euergesia</em> is the Greek civic-benefaction term: the vocabulary of public benefactors who performed services for the city. Peter reframes the Sanhedrin's legal inquiry as a question about a beneficent deed. The healed man's presence throughout the proceedings (v.14 — 'standing there with them') provides the visible, living evidence that cannot be dismissed. Josephus uses <em>euergesia</em> language in describing miraculous healers, situating Peter's vocabulary in contemporary religious discourse.</p>",
"10": "<p>'Jesus Christ of Nazareth, whom you crucified but whom God raised from the dead' — Peter names the precise historical acts of two specific agents: the Sanhedrin's action (crucifixion) and God's action (resurrection). The geographical designation 'of Nazareth' (<em>Nazōraios</em>) appears in the accusation placard on the cross (John 19:19) and throughout Acts as a precise identification tag that prevents confusion. The naming of the healers' identity follows the legal convention of specifying the full name and origin of the authority invoked.</p>",
"11": "<p>Psalm 118:22 ('the stone the builders rejected has become the cornerstone') was already a recognized messianic proof-text in early Judaism (cf. 1QS 8:7-8 from Qumran; 1 En. 62:3). Jesus himself quoted it against the Sanhedrin (Luke 20:17). The cornerstone (<em>kephalē gōnias</em> — head of the corner) is the foundation stone that determines the building's alignment. Luke's insertion of the Psalm citation into Peter's Sanhedrin speech maps the rejection-and-vindication pattern onto the specific legal situation: the Sanhedrin plays the role of the builders who rejected, God plays the role of the architect who vindicated.</p>",
"12": "<p>'Salvation is found in no one else, for there is no other name under heaven given to mankind by which we must be saved' — the universalism of the claim ('no other name') stands in deliberate tension with the Jewish particularism of the Sanhedrin setting. The <em>dei</em> (must be saved — divine necessity) frames salvation through Jesus's name as the divinely ordained mechanism, not one option among many. In the first-century context where Hellenistic religion offered a pluralistic market of saving deities, this exclusive claim was culturally radical as well as theologically decisive.</p>",
"13": "<p>'Unschooled, ordinary men' (<em>agrammatoi kai idiōtai</em>) — <em>agrammatoi</em> are those without formal scribal/legal training (not illiterate, since most Jewish males could read); <em>idiōtai</em> are laymen without professional expertise (in rhetorical contexts, non-specialists). The Sanhedrin's astonishment at the quality of Peter and John's reasoning despite their lack of formal training mirrors the Galilean fishermen's surprise role throughout Luke-Acts. Josephus mentions the Galileans' reputation for rough directness in contrast to the sophistication of Jerusalem's educated classes (<em>Vita</em> 37).</p>",
"14": "<p>The healed man's presence with the apostles (the same man who had lain at the Beautiful Gate for years — Acts 3:2; known to all Jerusalem, v.16) was epistemically decisive: no verbal defense was needed or possible against a living miracle. Josephus describes similar moments in legal proceedings where physical evidence (living witnesses, cured bodies) silenced legal objection (<em>Ant.</em> 17.6.4). The Sanhedrin's inability to deny the <em>sēmeion</em> (notable sign/miracle, v.16) shapes their subsequent strategy from legal refutation to social suppression.</p>",
"15": "<p>The Sanhedrin's deliberation 'among themselves' (<em>anakrinantes... en tō synedriō</em>) follows normal judicial procedure: the council conferred privately before issuing a ruling. The deliberative process (vv.15-17) shows the Sanhedrin functioning as a legal body recognizing the constraints of evidence: they cannot deny the sign (v.16), cannot punish the apostles without popular backlash (v.21), and cannot allow the movement to continue (v.17). The solution — a non-punitive injunction — was the least-damage option available given their legal and political constraints.</p>",
"16": "<p>'A notable sign' (<em>gnōston sēmeion</em> — a known/recognized miracle) — the Sanhedrin's private admission that a genuine miracle occurred is historically significant: the opponents of the apostles do not deny the miracle but attempt to suppress its interpretation. This pattern — conceding the fact while disputing the meaning — appears in rabbinic discussions of Jesus's miracles (b. Sanhedrin 43a, where Jesus's miracles are attributed to sorcery). The Sanhedrin's own acknowledgment of the sign is Luke's strongest authentication of the healing narrative.</p>",
"17": "<p>The injunction 'not to speak or teach at all in the name of Jesus' — <em>mē phenggesthai mēde didaskein epi tō onomati tou Iēsou</em> — uses <em>phthengesthai</em> (to produce sound, to utter — a stronger term than ordinary speech) combined with <em>didaskein</em> (to teach). The double prohibition covers both informal speech and formal instruction. The 'name' (<em>onoma</em>) is the operative legal concept: invoking Jesus's name in healing, preaching, or teaching is what the injunction targets. The focus on the name reflects the Sanhedrin's understanding that authority-claims made in Jesus's name were the movement's operational mechanism.</p>",
"18": "<p>The formal command (<em>parēngeilan... mē phenggesthai mēde didaskein</em>) is a legal injunction (<em>paraggelia</em> — an official order, the same word used for military commands and magistrates' directives). Peter and John's response in vv.19-20 constitutes a public refusal to comply — a dangerous legal position that the Sanhedrin could not immediately punish because of popular support (v.21). The dilemma of complying with human authority vs. divine command will recur in 5:29.</p>",
"19": "<p>'Which is right in God's eyes: to listen to you or to him?' (<em>ei dikaion estin enōpion tou theou hymōn akouein mallon ē tou theou krinete</em>) — Peter's formulation follows the Socratic pattern of appealing to a higher moral authority than the current tribunal: the question of what is <em>dikaion</em> (right/just) before God supersedes what is legal before the Sanhedrin. Socrates made a similar appeal at his trial (Plato, <em>Apology</em> 29d — 'I shall obey the god rather than you'). The structural parallel was likely intentional in Luke's presentation of Peter as a philosopher-martyr type.</p>",
"20": "<p>'We cannot help speaking about what we have seen and heard' (<em>ou dynametha hēmeis ha eidamen kai ēkousamen mē lalein</em>) — the combination of eyewitness categories (<em>eidamen</em> = what we saw; <em>ēkousamen</em> = what we heard) is the standard formula for legally valid testimony in antiquity: two senses, two modes of perception. Peter and John claim not theological conviction but empirical witness — they are reporting what happened, and reporting it under legal compulsion would be impossible. The <em>ou dynametha</em> (we are not able/cannot) frames the speech as a necessity, not a preference.</p>",
"21": "<p>'All the people were praising God for what had happened' — popular support was the Sanhedrin's primary constraint throughout Acts 1-6. The <em>laos</em> (the people of Israel as a covenant body, distinct from the <em>ethnē</em>/Gentiles) who support the apostles represent the same political reality that had constrained the Sanhedrin from arresting Jesus during the temple days (Luke 19:47-48; 20:19). The healed man being 'over forty years old' (v.22) adds to the evidentiary weight: a disability of four decades' standing, known to all Jerusalem, had been instantly removed.</p>",
"22": "<p>The man's age ('over forty years old') serves several narrative functions: it establishes the severity and duration of the disability (the longer the condition, the greater the miracle), it confirms that the healing could not be dismissed as psychosomatic or temporary (four decades of atrophied muscles restored instantly), and it gives the readers a verifiable detail that anchors the account in historical memory. Luke's characteristic precision with numbers (2:41 — three thousand; 4:4 — five thousand; 27:37 — 276 people) reflects his stated historiographical method (Luke 1:1-4).</p>",
"23": "<p>'Went back to their own people' (<em>pros tous idious</em>) — the community of believers to whom Peter and John returned is the Jerusalem church assembled somewhere near the temple. The full report of 'what the chief priests and the elders had said' (<em>hosa pros autous hoi archiereis kai hoi presbyteroi eipan</em>) triggers the corporate prayer of vv.24-30. The pattern: individual apostolic action → corporate response → communal prayer → divine confirmation (the shaking of the place, v.31). Luke consistently presents the early community as a praying corporate body rather than a loose collection of individuals.</p>",
"24": "<p>'Sovereign Lord (<em>Despota</em>), you who made the heavens and the earth and the sea and everything in them' — <em>Despota</em> is the absolute-sovereignty title for God, contrasting with <em>Kyrios</em> (Lord, the relational covenant-name). The prayer's opening creation-invocation ('maker of heaven and earth and sea and everything in them') cites Exod 20:11 and Psalm 146:6 verbatim from the LXX — the community prays in scripture-words, invoking the God who controls all creation to act within the specific historical crisis they face. The creation claim is the basis for the prayer: the One who made everything can act in everything.</p>",
"25": "<p>The prayer attributes Psalm 2 to 'your servant our father David' (<em>tou paidos sou Dauid</em>) through the Holy Spirit's mouth — a claim about the nature of scriptural inspiration. The same formulaic attribution appears in the DSS (4QFlor 1:11-13 attributes Psalm 2 to David) and Mishnah citations. Psalm 2 was widely used in early Judaism as a messianic text: the 'nations raging' and 'rulers gathering against the LORD and his anointed' (v.26 — <em>kata tou Kyriou kai kata tou Christou autou</em>) provided the interpretive frame for understanding the crucifixion as anticipated in scripture.</p>",
"26": "<p>The application of Psalm 2's 'kings of the earth' (<em>hoi basileis tēs gēs</em>) and 'rulers' (<em>hoi archontes</em>) to the specific historical cast of the crucifixion — Herod Antipas (tetrarch, v.27), Pontius Pilate (Roman governor), Gentiles (Roman soldiers), and 'the people of Israel' (the Jerusalem crowd) — is a remarkably precise historical-typological reading. Luke 23:6-12 records Herod and Pilate's collaboration during Jesus's trial; the prayer's citation applies the psalm to a scene documented in the Gospel. The application method is pesher-style exegesis (contemporary-historical fulfillment of ancient text), the same technique used at Qumran.</p>",
"27": "<p>'Herod and Pontius Pilate met together with the Gentiles and the people of Israel' — the fourfold listing of the crucifixion's human agents (Herod Antipas, Pilate, Gentiles/Romans, and Jewish crowd) maps perfectly onto the Psalm 2 categories (kings + rulers + nations + peoples). Luke 23:6-12 narrates the Herod-Pilate collaboration; the prayer in Acts 4 interprets it through the psalm. The theological claim is significant: all human agents who participated in the crucifixion were, without knowing it, fulfilling a predetermined divine script.</p>",
"28": "<p>'They did what your power and will had decided beforehand should happen' (<em>poiēsai hosa hē cheir sou kai hē boulē sou proōrisen genesthai</em>) — the <em>proorismos</em> (predetermination/foreordaining) of the crucifixion as an act of divine <em>boulē</em> (will/counsel) is the early church's theodicy for the cross: God did not fail to prevent it but used it as the instrument of redemption. The same concept appears in Acts 2:23 ('handed over by God's deliberate plan and foreknowledge') and reflects the early church's primary theological task: explaining how the death of the Messiah was consistent with divine sovereignty.</p>",
"29": "<p>'Enable your servants to speak your word with great boldness' (<em>parrēsia</em>) — <em>parrēsia</em> (bold free-speech, speaking without concealment) was the Athenian democratic virtue of frank public speech. In the context of a legal injunction commanding silence, requesting <em>parrēsia</em> is a prayer for the freedom to disobey the Sanhedrin's order. The prayer does not request the removal of the threat but the courage to face it — a pattern of petition (not for relief but for endurance) that appears throughout the Psalms (Ps 27:1; 31:1; 56:4, 11) and Paul's prison letters (Phil 1:20; 4:11-13).</p>",
"30": "<p>'Stretch out your hand to heal and perform signs and wonders through the name of your holy servant Jesus' — the imagery of God's 'outstretched hand' (<em>en tō tēn cheira ekteinein se</em>) is the Exodus vocabulary for divine intervention: the ten plagues are enacted through God's extended hand (Exod 3:20; 4:4; 7:5; 9:3; Deut 4:34; 5:15; 7:19). The prayer invokes the Exodus God to perform new-exodus signs through Jesus's name, explicitly linking the apostolic healing ministry to the foundational narrative of Israel's liberation from Egypt.</p>",
"31": "<p>The place being 'shaken' (<em>ekaleuthe ho topos</em>) after prayer is a theophany-sign throughout the OT: earthquake accompanies divine presence at Sinai (Exod 19:18; Ps 68:8), in prophetic visions (Isa 6:4; Ezek 38:19-20), and at the resurrection (Matt 28:2). The shaking of the prayer-meeting location fulfills the petition of v.29-30: God answers their prayer for boldness with a physical sign of divine presence. 'They were all filled with the Holy Spirit' — the repetition of the Pentecost-formula (2:4) signals that this post-arrest prayer meeting is a second Pentecostal filling for the same community.</p>",
"32": "<p>'All the believers were one in heart and mind' (<em>tou de plēthous tōn pisteusantōn ēn kardia kai psychē mia</em>) — the idealized description of the community in 4:32-35 is one of Luke's three community-summaries (2:42-47; 4:32-35; 5:12-16). The phrase 'one in heart and mind' (<em>kardia kai psychē mia</em>) echoes Aristotle's description of perfect friendship (<em>NE</em> 9.8 — 'a friend is another self') and Deuteronomy's 'love God with all your heart and soul' (Deut 6:5). The community-of-goods arrangement described here is not compulsory communism (Peter's rebuke of Ananias in 5:4 confirms that property remained private) but voluntary sharing.</p>",
"33": "<p>'God's grace was so powerfully at work in them all' (<em>charis te megalē ēn epi pantas autous</em>) — <em>charis</em> here functions in two registers: the theological sense (divine favor) and the social-political sense (favor/goodwill in the community). Luke's usage parallels the use of <em>charis</em> for favor both with God and with people (Luke 2:52 — Jesus grew in wisdom and in <em>charis</em> with God and people). The community's social cohesion and external reputation are here attributed to the same grace that produces their theological unity: <em>charis</em> is the operative force in both dimensions.</p>",
"34": "<p>'There were no needy persons among them' (<em>gar endees tis en en autois</em>) — the verbal echo of Deuteronomy 15:4 ('there should be no poor among you') is deliberate: the messianic community instantiates the Deuteronomic ideal for Israel's covenant life. The mechanism (selling land and houses, distributing to anyone who had need) resembles the Essene community's sharing arrangements described by Josephus (<em>J.W.</em> 2.8.3-4) — both movements response to the same Deuteronomic ideal, though with different institutional structures. The voluntary and occasional nature ('from time to time' — <em>hosoi ktētores... epipraskon</em>) distinguishes this from the Essene's permanent communal ownership.</p>",
"35": "<p>The 'apostles' feet' (<em>para tous podas tōn apostolōn</em>) as the receiving point for the community's funds reflects the ancient custom of placing gifts at a leader's feet as an act of submission and honor (Gideon receiving gold earrings in Judg 8:24-25; tribute placed at the feet of rulers throughout ancient Near Eastern imagery). The apostolic administration of the common fund is consistent with the Twelve's role as community leaders whose authorization legitimizes both the giving and the distribution. Acts will later (6:1-6) show this arrangement requiring structural adjustment as the community grows.</p>",
"37": "<p>The field sale by Barnabas (v.36-37) provides the paradigmatic positive example of the community practice just described — immediately before the negative counter-example of Ananias and Sapphira (5:1-11). Luke's pairing of exemplary and cautionary cases (Barnabas // Ananias, Simon Magus // the lame man) is a consistent narrative technique. Barnabas's Levitical identity (a Levite from Cyprus) is noteworthy: Levites technically were not to own inherited land in Israel (Num 18:20-24; Deut 10:9), but diaspora Levites owned property in their diaspora locations without this restriction applying.</p>"
},
"5": {
"1": "<p>The Ananias and Sapphira episode (5:1-11) immediately follows the paradigmatic community sharing of 4:32-37. The structural juxtaposition — community ideal (4:32-35), positive example (4:36-37 Barnabas), negative counter-example (5:1-11) — is Luke's moral-exemplary technique, common in Hellenistic historical writing (<em>exempla</em> / <em>paradeigmata</em>). Ananias (<em>Ḥananyah</em> — 'YHWH is gracious') and Sapphira (<em>Shappirah</em> — 'beautiful' in Aramaic) are Jewish names; the couple are members of the covenant community, not outsiders. Their sin is internal — covenant-community betrayal, not pagan opposition.</p>",
"2": "<p>'With his wife's full knowledge he kept back part of the money' (<em>enosphisato apo tēs timēs syneidyias kai tēs gynaikos</em>) — <em>nosphizomai</em> (to pilfer, to keep back for oneself) is the LXX word for Achan's keeping back of devoted goods at Jericho (Josh 7:1 LXX — <em>enosphisanto</em>); Luke's word-choice signals that the Ananias episode is a new-Achan story. Achan's sin (withholding from <em>ḥerem</em>/the devoted thing) is the defining act of covenant-betrayal that disrupted Israel's conquest. The parallel frames the Jerusalem community as a new covenant body whose integrity is similarly at stake.</p>",
"3": "<p>'Satan has so filled your heart' (<em>ti hoti eplērōsen ho Satanas tēn kardian sou</em>) — the direct attribution of Ananias's action to Satanic influence parallels Judas's betrayal ('Satan entered into Judas,' Luke 22:3). The Satan-filling language does not remove human moral responsibility (v.4 — 'you have not lied to men but to God' confirms Ananias's culpability); it frames the deception as a manifestation of the cosmic adversary's work within the covenant community. 'To lie to the Holy Spirit' (<em>pseusasthai se to pneuma to hagion</em>) identifies the Spirit as the community's governing presence — lying to the community's shared fund is lying to the Spirit who inhabits the community.</p>",
"4": "<p>'It belonged to you... wasn't the money at your disposal?' — Peter's twofold rhetorical affirmation establishes that the sin was not failure to donate but deception about the donation. The property was Ananias's own before the sale and the proceeds were at his disposal after (<em>en tē sē exousia hypērchen</em>); no compulsion existed. The Qumran community's rule on property retention provides an illuminating contrast: the Damascus Document (CD 9:13-15) mandated full disclosure of retained property but allowed staged donation over multiple years. Luke's account implies no such staged system; the Jerusalem community's sharing was voluntary and unregulated, making deception rather than retention the offense.</p>",
"5": "<p>Ananias's instant death (<em>exepsyxen</em> — breathed out, expired) when hearing Peter's judgment parallels the immediate death of Achan's household at Jericho (Josh 7:24-26) and Uzzah's death for touching the ark (2 Sam 6:6-7). Luke does not speculate on the mechanism — natural, miraculous, or divine fiat — but records the fact and its effect: 'great fear seized all who heard' (<em>phobos megas</em>). The <em>phobos megas</em> formula appears at every major divine-action event in Luke-Acts (1:12; 2:43; 5:5, 11; 19:17) as the appropriate human response to immediate divine presence and action.</p>",
"6": "<p>'Young men (<em>neoteroi</em>) came forward, wrapped up his body' — the <em>neoteroi</em> (younger men, the junior members of the community) perform the burial — the customary role of the young in Jewish burial practice. Jewish custom required burial on the day of death whenever possible (m. Sanhedrin 6:5; Deut 21:23 — 'you shall not leave his body... overnight but shall bury him the same day'). The speed (no time to notify Sapphira, who arrives three hours later knowing nothing) is consistent with this practice.</p>",
"7": "<p>'About three hours later his wife came in, not knowing what had happened' — Sapphira's ignorance of her husband's death (three hours is enough time for the burial of v.6 but apparently not enough for news to reach her) provides the narrative occasion for Peter's separate test and judgment. The three-hour gap may reflect the distances involved in the Jerusalem community's spread across the city, or the community's deliberate decision not to inform her. Peter's question ('Tell me, is this the price...?') constitutes both a test and a judgment-scenario: she has an opportunity to tell the truth.</p>",
"8": "<p>Peter's question ('is this the price you and Ananias got for the land?') is a test offering Sapphira the opportunity to break with her husband's deception. The couple's 'full knowledge' (<em>syneiduias</em>, v.2) of the deception is retested now in the husband's absence — will she maintain the lie without him? Her confirmation of the false price (<em>nai, tosoutou</em> — 'yes, that much') is the moment of judgment. The judicial structure (accusation, opportunity to speak, judgment, execution) mirrors formal legal proceedings.</p>",
"9": "<p>'How could you conspire to test the Spirit of the Lord?' (<em>ti hoti synephōnēthē hymin peirasai to pneuma Kyriou</em>) — <em>synephōnēthē</em> (to agree-together, to conspire) is the conspiracy-word: the couple's agreement to deceive constitutes a coordinated test of the Holy Spirit's capacity to detect falsehood. 'Testing the Spirit of the Lord' (<em>peirasai to pneuma Kyriou</em>) echoes Israel's testing of God in the wilderness (Exod 17:2, 7; Num 14:22; Ps 95:9; Heb 3:8-9) — the deliberate provocation of a known divine presence to see if it will actually act.</p>",
"10": "<p>Sapphira's death 'at Peter's feet' (<em>pros tous podas autou</em>) exactly mirrors the location of the community's financial offerings (4:35 — 'laid at the apostles' feet'). The spatial irony is Luke's: the location of voluntary giving becomes the location of involuntary judgment. The young men's return to find her dead and their burial of her alongside her husband completes the chiastic structure: the couple who conspired together in deception die apart (three hours between the deaths) but are buried together (<em>pros ton andra autēs</em> — beside her husband).</p>",
"11": "<p>'Great fear seized the whole church (<em>ekklēsia</em>) and all who heard about these events' — this is the first use of <em>ekklēsia</em> in Acts (the term that will become the standard word for the Christian community worldwide). The term had both a civic sense (the democratic assembly of citizens in a Greek polis, Acts 19:39-41) and an LXX sense (the assembly/congregation of Israel, used 73x in the LXX). Luke's use here positions the Jerusalem community as both a civic assembly and the continuation of Israel's covenant assembly. The <em>phobos megas</em> that falls on both the church and the wider community mirrors the fear after Pentecost (2:43).</p>",
"12": "<p>'Solomon's Colonnade' (<em>stoa Solomōnos</em>) — the eastern portico of the outer temple court, associated with Solomon's original temple and retained in Herod's rebuilding. Josephus describes it as the oldest structure remaining from Solomon's period (<em>Ant.</em> 15.11.3; 20.9.7). The portico provided covered space for large gatherings and was the site of Jesus's winter teaching (John 10:23) and the early community's daily assembly. The apostles' use of the Solomon's Colonnade creates continuity with both Jesus's temple ministry and Israel's longest-standing architectural tradition.</p>",
"13": "<p>'No one else dared join them, even though they were highly regarded by the people' — the tension between being 'highly regarded' (<em>emegalynen autous ho laos</em> — the people were magnifying them) and no outsider 'daring to join' (<em>tolma kollasthai autois</em>) reflects the community's ambiguous social status after the Ananias episode. The 'fear' of v.11 had a deterrent effect on casual adherents; the price of entry (genuine commitment under divine scrutiny) was now visible. Despite this deterrent, v.14 reports continued numerical growth — a distinction between casual association and genuine membership.</p>",
"14": "<p>'More and more men and women believed in the Lord and were added to their number' — the gender-explicit listing (<em>andres te kai gynaikes</em> — men and women) is characteristic of Luke's careful attention to female inclusion (Luke 8:1-3; 24:10-11; Acts 1:14; 2:17-18; 9:36-42; 16:13-15; 18:26). The numerical growth despite — or because of — the Ananias episode demonstrates Luke's consistent pattern: divine discipline produces community integrity, which produces credibility, which produces growth.</p>",
"15": "<p>'Peter's shadow might fall on them as he passed by' — the contact-healing through Peter's shadow has no direct OT parallel but reflects the popular understanding that <em>dynamis</em> (power) radiated from holy persons. Josephus mentions similar expectations attached to Elisha's bones (2 Kgs 13:21 — the dead man revived when he touched Elisha's bones; <em>Ant.</em> 9.8.6). In the Hellenistic world, the shadows and garments of wonder-workers were attributed healing properties. Luke does not confirm that Peter's shadow itself healed (he says people 'laid out' the sick hoping for it) but records the popular behavior without theological comment.</p>",
"16": "<p>'Tormented by impure spirits' (<em>ochloumenous hypo pneumatōn akathartōn</em>) — the geography of the healings expands beyond Jerusalem to 'the towns around Jerusalem' (<em>tōn peri Ierousalēm poleōn</em>). The same movement from Jerusalem outward characterizes the mission as a whole (1:8 — Jerusalem → Judea → Samaria → ends of earth). The specific mention of 'impure spirits' alongside diseases distinguishes the apostolic healing ministry as covering both domains of human affliction: physical illness and demonic oppression. Both are healed/expelled (<em>etherapeunto apantes</em> — all were being healed).</p>",
"17": "<p>'The high priest and all his associates, who were members of the party of the Sadducees, were filled with jealousy' (<em>plēsthēsan zēlou</em>) — <em>zēlos</em> (zeal/jealousy) is a powerful motivator in ancient Jewish literature: the zeal of Phinehas (Num 25:11) and the Maccabean warriors were celebrated as righteous; but jealousy-<em>zēlos</em> (the destructive envy of another's success) was condemned. The high priest's party acts from <em>zēlos</em> — rivalry with a successful popular movement — rather than genuine theological concern. Luke's characterization is pointed: the Sadducean establishment responds to miraculous success with envy.</p>",
"18": "<p>The arrest of 'the apostles' (the plural, not just Peter and John as in ch.4, suggesting a wider arrest) and their placement in the 'public jail' (<em>tērēsei dēmosia</em> — public custody, as distinct from a private or temple jail) escalates the previous individual arrest (4:3). The public jail is the Roman-administered prison of Jerusalem, more severe than the Sanhedrin's own detention facilities. The escalation pattern (arrest → release → re-arrest → flogging → eventual martyrdom) follows the progression typical of Roman persecution of unauthorized religious movements.</p>",
"19": "<p>The angel of the Lord who opens the prison doors (<em>angelos Kyriou dia nyktos ēnoixen tas thyras tēs phylakēs</em>) belongs to the 'divine rescue' genre widespread in Jewish literature (Dan 3; 6; Judith 13; <em>3 Macc.</em> 6:18-21) and Hellenistic romances (Euripides, <em>Bacchae</em> 443-444; Ovid, <em>Metamorphoses</em>). Luke is not borrowing the genre but deploying it as typology: the God who rescued Daniel from the lions and Israel from Egypt now rescues the apostles from the Sanhedrin's custody. The angel's instruction ('go, stand in the temple courts') redirects the apostles immediately to the scene of their previous teaching.</p>",
"20": "<p>'Tell the people all about this new life' (<em>lalōtte... panta ta rhēmata tēs zōēs tautēs</em> — speak all the words of this life) — <em>zōē</em> (life) here is eschatological life, the resurrection-life that the apostles proclaim as having begun in Jesus. The instruction to return immediately to the temple courts (rather than flee Jerusalem) is significant: the divine rescue is not an escape from the mission but an enabling of its continuation. The apostles are returned to the exact location of the confrontation to resume exactly the activity that produced the confrontation.</p>",
"21": "<p>'At daybreak they entered the temple courts, as they had been told' — the apostles' early-morning temple entry corresponds to the temple's opening hours: the gates were opened at dawn for the morning sacrifice. The Sanhedrin's simultaneous convening ('the full assembly of the elders of Israel' — <em>synedrion kai pasan tēn gerousian tōn huiōn Israēl</em>) for the apostles' formal trial creates the dramatic irony: the council assembles to try prisoners who are already free and preaching.</p>",
"22": "<p>'The officers did not find them there' — the empty jail parallels the empty tomb: in both cases, the expected prisoner/body is absent, guarded doors are found locked, and the first witnesses are confused by the absence (Luke 24:3-4 — 'they did not find the body... two men in gleaming clothes stood beside them'). Luke's narrative echoes are deliberate: the apostles' prison-release participates in the same resurrection pattern that their preaching proclaims.</p>",
"23": "<p>'We found the jail securely locked, with the guards standing at the doors' — the guards' detailed report emphasizes the security of the containment: the <em>phulakē</em> (jail) was locked (<em>kekleismenēn en pasē asphaleia</em> — locked with all security) and the guards were at their posts. The impossibility of ordinary escape is Luke's apologetic point: no natural explanation (bribed guards, hidden exits, complicit jailers) accounts for the empty locked cell. The report mirrors the empty-tomb apologetic in Matthew 28:11-15 (guards bribed to deny the resurrection).</p>",
"24": "<p>'The captain of the temple guard and the chief priests were at a loss (<em>diēporoun</em> — thoroughly perplexed/at a complete loss), wondering what this might develop into' (<em>ti an genoito touto</em>) — <em>diaporeomai</em> (to be completely at a loss) is Luke's word for the disciples' bewilderment at the resurrection (Luke 24:4) and the crowd's at Pentecost (Acts 2:12). The same theological confusion that accompanied the resurrection now accompanies the prison-release that proclaims the resurrection. The authorities who orchestrated the containment cannot explain the escape.</p>",
"25": "<p>The news that the imprisoned apostles are 'standing in the temple courts teaching the people' is delivered mid-Sanhedrin session as a messenger's intrusion — the dramatic timing maximizes the council's embarrassment. The apostles' location 'in the temple courts' (<em>en tō hierō</em>) is the most public and religiously significant space in Jerusalem: they have returned not to a private house but to the center of Jewish religious life, teaching as if they have never left.</p>",
"26": "<p>'They did not use force, because they feared that the people might stone them' — the Sanhedrin's officers bring the apostles 'without force' (<em>ou meta bias</em>) because they fear the crowd (<em>lithasthōsin — might be stoned</em>). The threat of stoning by the people reverses the Sanhedrin's institutional power: the council that has authority to stone the apostles dare not arrest them forcefully because the crowd might stone the council. The reversal of stoning-threat is one of Luke's consistent ironies in Acts 1-7 (prior to Stephen's actual stoning).</p>",
"27": "<p>The second Sanhedrin appearance is more formal than the first (4:5-22): now the 'full assembly' (<em>pan to synedrion</em>) is convened, the charge is more specific (v.28), and the intended punishment is death (v.33). The pattern of escalating persecution mirrors the progression in the Synoptic Passion narrative (interrogation → formal trial → execution), and Luke's structuring of the apostolic persecution as a passion-parallel is intentional.</p>",
"28": "<p>'You have filled Jerusalem with your teaching' (<em>peplērōkate tēn Ierousalēm tēs didachēs hymōn</em>) — the high priest's accusation is simultaneously an inadvertent compliment: the apostolic mission has saturated the city. The charge of 'bringing this man's blood upon us' (<em>epagagein eph' hēmas to haima tou anthrōpou toutou</em>) echoes Matthew 27:25 ('his blood be on us and our children') — the Sanhedrin fears the legal and moral consequences of having authorized the crucifixion. The refusal to name Jesus ('this man') reflects both contempt and a kind of superstitious avoidance.</p>",
"29": "<p>'We must obey God rather than human beings' (<em>peitharchein dei theō mallon ē anthrōpois</em>) — the formulation is structurally identical to 4:19 but now uses <em>peitharchein</em> (to obey authority) rather than <em>akouein</em> (to listen/hear). The <em>dei</em> (must/necessity) frames apostolic disobedience as a divine necessity: they cannot choose otherwise. Plato attributes a similar principle to Socrates (<em>Apology</em> 29d); Philo applies it to Jewish resistance to Caligula's demands (<em>Legatio</em> 196-197). The principle — human law yields to divine law when they conflict — was recognized across Hellenistic Jewish and Greek ethical traditions.</p>",
"30": "<p>'The God of our ancestors raised Jesus from the dead — whom you killed by hanging him on a tree (<em>xylon</em>)' — <em>xylon</em> (tree/wood) rather than <em>stauros</em> (cross) invokes Deuteronomy 21:23 ('anyone who is hung on a tree is under God's curse') — as Paul makes explicit in Galatians 3:13. The Deuteronomic curse-of-the-tree was the Sanhedrin's argument that Jesus's crucifixion proved his divine rejection. Peter's use of <em>xylon</em> appropriates the Deuteronomic language and reframes it: the one hung on the tree was raised by the God of the ancestors, reversing the curse's implication.</p>",
"31": "<p>'God exalted him to his own right hand as Prince (<em>archēgos</em>) and Saviour (<em>sōtēr</em>)' — <em>archēgos</em> (pioneer/prince/leader/founder) appears in 3:15 ('author of life'), and in Hebrews 2:10 ('pioneer of salvation') and 12:2 ('pioneer and perfecter of faith'). The title combines the sense of one who goes first/ahead (pioneer) with one who rules (prince/leader). <em>Sōtēr</em> (saviour) is the imperial title claimed by Augustus and subsequent emperors; Luke's application of it to Jesus via the Sanhedrin-speech is a counter-imperial designation. 'To give repentance and forgiveness of sins' — the purpose of the exaltation is the provision of the gifts that bring Israel back to covenant relationship.</p>",
"32": "<p>'We are witnesses of these things, and so is the Holy Spirit, whom God has given to those who obey him' — the apostolic witness (<em>martyres</em>) and the Spirit's witness are presented as two distinct but coordinated testimonies to the same facts. The witness-theology follows Deuteronomy 17:6 and 19:15 (two or three witnesses required for legal testimony): the human witnesses (apostles) plus the divine witness (Spirit) constitute the required two-testimony basis for the resurrection claim. The condition 'to those who obey him' (<em>tois peitharchounsin autō</em>) uses the same <em>peitharchein</em> as v.29 — the Spirit is given to those who practice the apostolic obedience-to-God-rather-than-men.</p>",
"33": "<p>'They were furious and wanted to put them to death' (<em>dieprionto kai eboulonto anelein autous</em>) — <em>dieprionto</em> (were sawn-through, cut to the quick) is a vivid image for extreme internal agitation — the emotion that will also describe the Sanhedrin's reaction to Stephen (7:54 — <em>dieprionto tais kardiais autōn</em>). The progression from legal injunction (4:18) to flogging (5:40) to the intended death that only Gamaliel's intervention prevents mirrors the escalation that will end in Stephen's stoning. The Sanhedrin moves through available legal remedies toward extrajudicial violence.</p>",
"35": "<p>Gamaliel's speech structure follows the standard Hellenistic deliberative rhetorical form: (1) directive to remove the accused from hearing (v.34), (2) statement of the principle at stake (v.35), (3) historical examples (vv.36-37), (4) conclusion drawn from the examples (vv.38-39). The paired historical examples (Theudas + Judas the Galilean) are the <em>exempla</em> central to deliberative argument. The speech's purpose — to interrupt the slide toward judicial murder — is rhetorically achieved: the Sanhedrin is persuaded to substitute flogging for execution (v.40).</p>",
"36": "<p>The Theudas reference has troubled historians: Josephus places Theudas under the procuratorship of Fadus (44-46 CE; <em>Ant.</em> 20.5.1), which would be after Gamaliel's speech (ca. 30-35 CE) and after the 'Judas the Galilean' rebellion of 6 CE (which Gamaliel places 'after him'). The most common solutions: (1) Luke made a chronological error; (2) Luke's Theudas was a different Theudas from Josephus's; (3) Josephus's chronology has its own problems. The name Theudas (<em>Thaddaios</em>) was common enough that multiple figures with this name existed in the turbulent first-century Palestinian Jewish political landscape.</p>",
"37": "<p>'Judas the Galilean appeared in the days of the census' — the census of Quirinius (6 CE) and Judas the Galilean's revolt is described by Josephus (<em>Ant.</em> 18.1.1; 20.5.2; <em>J.W.</em> 2.8.1). Judas founded what Josephus calls the 'Fourth Philosophy' — a movement combining Pharisaic theology with resistance to Roman rule on the grounds that God alone was Israel's king. The movement's violent end ('he too was killed, and all his followers were scattered') matches Josephus's description. The historical reference grounds Gamaliel's argument in recognizable recent history.</p>",
"38": "<p>'If their purpose or activity is of human origin, it will fail' (<em>ean ē ex anthrōpōn hē boulē hautē ē to ergon touto, katalythēsetai</em>) — Gamaliel's prudential argument is not a theological endorsement of the apostles but a tactical restraint: the test of divine origin is historical durability. The argument has the structure of a Rabbinic proof-from-consequence (<em>kal va-chomer</em> — if A (human movements fail), then B (wait to see if this movement fails)). The argument's limitation — it could validate any movement that survives long enough — is precisely what Gamaliel does not address; it was not his concern.</p>",
"39": "<p>'If it is from God, you will not be able to stop these men; you will only find yourselves fighting against God (<em>theomachoi</em>)' — <em>theomachos</em> (god-fighter) is a Greek concept with strong negative connotations: Euripides's <em>Bacchae</em> presents Pentheus as the paradigmatic <em>theomachos</em> who fights against Dionysus and is destroyed. Jewish tradition used <em>theomachein</em> for Pharaoh's resistance to YHWH (Philo, <em>Vit. Mos.</em> 1.96). The risk of being a <em>theomachos</em> is the most compelling deterrent Gamaliel can invoke before the Sanhedrin — no council wants to be recorded as having fought God and lost.</p>",
"40": "<p>'They called the apostles in and had them flogged' (<em>deirantes</em> — having beaten/flayed) — the flogging inflicted by the Sanhedrin was the 'forty lashes minus one' (<em>malkot</em>) prescribed in Deuteronomy 25:3 and described in m. Makkot 3:10-12. The sentence was a moderate judicial punishment within Jewish law, far short of execution (which Gamaliel had prevented). Paul will later reference receiving this punishment five times (2 Cor 11:24 — 'five times I received from the Jews the forty lashes minus one'). The apostles are released with both a punishment and a repeated injunction not to speak in Jesus's name.</p>",
"41": "<p>'Rejoicing because they had been counted worthy of suffering disgrace for the Name' (<em>katēxiōthēsan atimasthēnai hyper tou onomatos</em>) — the paradox of rejoicing at dishonor (<em>atimia</em>) for the sake of honor (<em>onoma</em>) is the martyr-theology of the beatitudes (Matt 5:11-12 — 'blessed are you when people insult you, persecute you... rejoice and be glad') applied to actual suffering. The suffering for 'the Name' (<em>hyper tou onomatos</em> — literally 'for the name,' without specifying whose) is the early Christian formula for suffering on account of Jesus's identity and authority. 3 Maccabees 6:30 and 4 Maccabees use similar language for Jewish martyrs.</p>",
"42": "<p>'Day after day, in the temple courts and from house to house, they never stopped teaching and proclaiming the good news that Jesus is the Messiah' — the dual-venue ministry (temple + house) describes the early Jerusalem church's bifurcated institutional life: public, formal proclamation in the publicly accessible temple courts; intimate, family-sized instruction in private homes (<em>kat' oikon</em> — home by home, house by house). This pattern anticipated the eventual expulsion from the temple and the shift to house-church-only structure that became normative for Christianity outside Jerusalem within a generation.</p>"
},
"6": {
"1": "<p>'Hellenistic Jews' (<em>Hellēnistai</em>) vs. 'Hebraic Jews' (<em>Hebraioi</em>) — one of the most debated distinctions in Acts scholarship. The primary distinction is linguistic: <em>Hellēnistai</em> are Greek-speaking diaspora Jews (or diaspora-origin Jews resident in Jerusalem); <em>Hebraioi</em> are Aramaic/Hebrew-speaking Palestinian Jews. The secondary implications include: different liturgical traditions (LXX vs. Hebrew Bible), different cultural orientations (Greek diaspora vs. Palestinian Jewish), and different social networks. The <em>Hellēnistai</em> include the Seven elected in this chapter (all with Greek names: Stephen, Philip, Prochorus, Nicanor, Timon, Parmenas, Nicolaus).</p>",
"2": "<p>'It would not be right for us to neglect the ministry of the word of God in order to wait on tables' (<em>ouk areston estin hēmas kataleipsantas ton logon tou theou diakonein trapezais</em>) — the Twelve's distinction between <em>diakonia logou</em> (ministry of the word) and <em>diakonia trapezōn</em> (ministry of tables/meals) is not a hierarchy of spiritual vs. material but a division of labor within the community. <em>Diakonia</em> is the same root that produces 'deacon' (<em>diakonos</em>); the Seven are the antecedents of the diaconal office in Christian tradition, though the word 'deacon' does not appear in this passage.</p>",
"3": "<p>'Seven men from among you who are known to be full of the Spirit and wisdom' — the number seven has institutional precedent: the <em>shivah tovei ha-ir</em> (seven good men of the city) was the standard municipal leadership board in Jewish communities, responsible for civic and charitable administration (m. Megillah 3:1; t. Megillah 3:1; Josephus, <em>Ant.</em> 4.8.14). The Seven of Acts may be modeled on this institution, adapting a recognized form of communal governance to the new context. The qualifications ('full of Spirit and wisdom') combine pneumatological fitness with practical competence.</p>",
"4": "<p>'Give our attention to prayer and the ministry of the word' (<em>tē proseukhē kai tē diakonia tou logou proskarterēsomen</em>) — <em>proskarterēsomen</em> (we will devote ourselves to, we will persist in) is the continuous-attention verb: the Twelve will sustain an ongoing, undistracted practice of prayer and word-ministry. Luke uses the same verb for the disciples' continuous prayer before Pentecost (1:14) and the Jerusalem church's devotion to apostolic teaching and prayer (2:42). The Twelve's withdrawal from table-service is not an abdication of practical responsibility but a focused intensification of the prayer-and-word ministry that makes the word-ministry productive.</p>",
"5": "<p>The election of seven men, all with Greek names, suggests either all-Hellenist appointees (addressing the Hellenist widows with leaders from their own community) or a deliberate cross-cultural selection. Nicolaus is specifically identified as 'a convert to Judaism from Antioch' (<em>proselytos Antiocheus</em>) — the only proselyte (former Gentile) among the Seven. This is the first appearance of Antioch in Acts, anticipating the Antioch mission of 11:19-26. Stephen and Philip receive extended individual narratives; the others are not mentioned again.</p>",
"6": "<p>'They presented these men to the apostles, who prayed and laid their hands on them' — the laying on of hands (<em>epitithēmi tas cheiras</em>) with prayer is the commissioning/ordination gesture used throughout the OT (Num 27:18-23 — Moses commissions Joshua by laying hands on him) and NT (Acts 8:17; 13:3; 1 Tim 4:14; 2 Tim 1:6). The gesture communicates transfer of authority, identification with the commissioned person, and invocation of divine blessing. Luke does not specify whether the whole community or just the Twelve laid hands on the Seven; both are grammatically possible from 'they presented them to the apostles, who prayed.'</p>",
"7": "<p>'The word of God spread. The number of disciples in Jerusalem increased rapidly, and a large number of priests became obedient to the faith' (<em>polys te ochlos tōn hiereōn hypēkouon tē pistei</em>) — the conversion of 'a large number of priests' is noteworthy: the priestly class was divided between Sadducees (who controlled the high-priestly offices) and ordinary priests (<em>hiereis</em>) who served rotational duty in the temple. The conversion of priests to the messianic movement created a community with substantial liturgical and theological expertise but disrupted the priestly establishment's institutional control. Josephus indicates that by the 60s CE the high priesthood was in severe tension with the ordinary priestly class (<em>Ant.</em> 20.8.8).</p>",
"8": "<p>'Stephen, a man full of God's grace and power, performed great wonders and signs among the people' — Stephen is the first of the Seven to receive extended narrative attention. His description ('full of grace and power') exceeds the original Seven's qualification ('full of Spirit and wisdom,' v.3) — Luke signals that Stephen is no ordinary table-server but an apostolic figure whose miracle-working ministry (the first attributed to anyone other than the Twelve in Acts) and theological confrontation with the Diaspora synagogues will drive the narrative toward Jerusalem's first martyr-death.</p>",
"9": "<p>The 'Synagogue of the Freedmen' (<em>synagōgē tōn Libertinōn</em>) — <em>Libertinoi</em> (Latin <em>libertini</em> = freed slaves) are Jews whose ancestors had been enslaved and brought to Rome, later freed. Pompey brought Jewish captives to Rome in 63 BCE; many were subsequently freed and formed synagogue communities. The specific groupings (Cyrenians, Alexandrians, Cilicians, and Asians) suggest distinct diaspora community-synagogues in Jerusalem — a common arrangement where diaspora pilgrims and permanent residents maintained ethnically/regionally defined congregations. Cilicia is Paul's home region; some scholars have suggested Paul may have debated in this synagogue.</p>",
"10": "<p>'They could not stand up against the wisdom the Spirit gave him as he spoke' (<em>ouk ischyon antistēnai tē sophia kai tō pneumati ō elalei</em>) — the combination of wisdom (<em>sophia</em>) and Spirit (<em>pneuma</em>) echoes the Seven's original qualifications (v.3 — 'full of Spirit and wisdom') and fulfills Jesus's promise in Luke 21:15 ('I will give you words and wisdom that none of your adversaries will be able to resist or contradict'). The opponents' inability to refute Stephen's arguments corresponds to the pattern established with Peter and John (4:14 — 'there was nothing they could say').</p>",
"11": "<p>'We have heard Stephen speak blasphemous words against Moses and against God' — blasphemy (<em>blasphēmia</em>) against the divine name was a capital offense (Lev 24:15-16; m. Sanhedrin 7:5). The charge that Stephen spoke against Moses (<em>kata Mōyseōs</em>) — the Torah-giver — and against God amplifies the charge: Stephen is accused of attacking both the human mediator of the covenant and the divine lawgiver himself. The false witnesses (v.13 — <em>martyras pseudeis</em>) parallel the false witnesses at Jesus's trial (Mark 14:55-59 — also charging temple-blasphemy), explicitly positioning Stephen's trial as a passion-narrative parallel.</p>",
"12": "<p>'They seized Stephen and brought him before the Sanhedrin' — the sequence (secret persuasion of false witnesses → stirring up the crowd, elders, and scribes → seizure → Sanhedrin appearance) follows the legal procedure for blasphemy cases outlined in the Mishnah (m. Sanhedrin 7:5): two witnesses required, public hearing, formal Sanhedrin trial. The stirring up of 'the people and the elders and the teachers of the law' (<em>ton laon kai tous presbyterous kai tous grammateis</em>) is a deliberate crowd-mobilization that will produce not a legal verdict but a lynching (7:57-58).</p>",
"13": "<p>'This fellow never stops speaking against this holy place and against the law' — the charge against Stephen contains two components: speaking against the temple ('this holy place') and against the Torah ('the law'). Stephen's defense-speech (ch.7) will address both: a sustained argument that the temple is not the necessary locus of divine presence (7:44-50) and that Israel has repeatedly failed to keep the Torah (7:2-53). The charge anticipates the content of what Stephen actually says — either the accusers are responding to genuine teachings of Stephen's, or Luke has structured the accusation to match the defense that follows.</p>",
"14": "<p>'This Jesus of Nazareth will destroy this place and change the customs Moses handed down to us' — the 'Jesus of Nazareth will destroy this place' accusation echoes Mark 14:58 / Matt 26:61's false witness at Jesus's trial ('I will destroy this temple made with human hands and in three days will build another, not made with hands'). Jesus's actual temple-prediction (Mark 13:2 / Luke 21:6 — 'not one stone here will be left on another') was prophetic, not a personal threat. The 'changing the customs Moses handed down' (<em>ta ethē ha paredōken hēmin Mōysēs</em>) charge is the precursor to the ongoing Jewish charge against Christianity of Torah-antinomianism.</p>",
"15": "<p>'All who were sitting in the Sanhedrin looked intently at Stephen, and they saw that his face was like the face of an angel' — the angelic face-transfiguration is a theophany-sign in Jewish literature: Moses's face shone with divine glory after his Sinai encounters (Exod 34:29-35); Dan 10:6 describes the heavenly messenger's face 'like lightning'; the DSS (<em>1QSa</em>) includes a face like an angel as a qualification. The Sanhedrin's involuntary recognition of Stephen's angelic appearance provides the theological frame for his defense: the one whose face looks like an angel is not a blasphemer but a divine messenger. The visual sign prepares for the vision of the Son of Man at 7:55-56.</p>"
}
}

def main():
    existing = load_comm('mkt-context', 'acts')
    merge_comm(existing, ACTS_CH4_6)
    save_comm('mkt-context', 'acts', existing)
    for ck in ['4', '5', '6']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
